import sailpoint.object.Identity;
import sailpoint.object.ProvisioningPlan;
import sailpoint.object.ProvisioningPlan.AccountRequest;
import sailpoint.object.ProvisioningPlan.AttributeRequest;
import sailpoint.object.ProvisioningPlan.Operation;
import sailpoint.object.ProvisioningPlan.AccountRequest.Operation;
import sailpoint.api.Provisioner;
import sailpoint.api.*;
import sailpoint.object.QueryOptions;
import sailpoint.object.Filter;
import sailpoint.workflow.WorkflowContext;

System.out.println("identityName: "+identityName);
Identity identity = context.getObjectByName(Identity.class, identityName);


System.out.println("identity: "+identity);

  String app = "HR System"; //LDAP
  String nativeIdentity = identityName;



  ProvisioningPlan plan = new ProvisioningPlan();
  // Set identity to the plan
  plan.setIdentity(identity);

  AccountRequest accReq = new AccountRequest();
  accReq.setOperation(AccountRequest.Operation.Disable);
  accReq.setApplication(app);
  accReq.setNativeIdentity(nativeIdentity);

  plan.add(accReq);

  //Provisioner p = new Provisioner(context);
  //p.execute(plan);

  System.out.println("Plan "+plan.toXml());
  workflow.put("plan", plan);


 wfcontext.setVariable("identityName", identityName);
 wfcontext.getVariable("identityName");

return plan;
